import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Input, Badge, Switch, icon } from 'decantr/components';

code.example:
function TierBuilder({ tiers: initialTiers = [], onSave }) {
  const { div, h2, h3, p, span, label, form } = tags;
  const [tiers, setTiers] = createSignal(initialTiers);
  const [editing, setEditing] = createSignal(null);
  const [newBenefit, setNewBenefit] = createSignal('');

  const defaultTier = { name: '', description: '', monthlyPrice: 0, yearlyPrice: 0, benefits: [], color: '#F97316', published: false };
  const [form_, setForm] = createSignal({ ...defaultTier });

  const editTier = (tier) => { setEditing(tier.id); setForm({ ...tier }); };
  const addBenefit = () => {
    if (newBenefit().trim()) {
      setForm({ ...form_(), benefits: [...form_().benefits, newBenefit().trim()] });
      setNewBenefit('');
    }
  };
  const removeBenefit = (i) => setForm({ ...form_(), benefits: form_().benefits.filter((_, idx) => idx !== i) });

  const saveTier = () => {
    if (editing()) {
      setTiers(tiers().map(t => t.id === editing() ? { ...form_(), id: editing() } : t));
    } else {
      setTiers([...tiers(), { ...form_(), id: crypto.randomUUID() }]);
    }
    setEditing(null);
    setForm({ ...defaultTier });
    onSave?.(tiers());
  };

  const deleteTier = (id) => setTiers(tiers().filter(t => t.id !== id));

  return div({ class: css('_grid _gc1 _lg:gc2 _gap6') },
    div({ class: css('_flex _col _gap4') },
      h2({ class: css('_heading4 _mb2') }, 'Your Tiers'),
      tiers().length === 0
        ? Card({ class: css('studio-card _p6 _tc _fgmuted') }, 'No tiers yet. Create your first tier!')
        : div({ class: css('_flex _col _gap3') },
            ...tiers().map((tier, i) =>
              Card({ class: css(`studio-card _p4 _flex _aic _gap4 ${editing() === tier.id ? '_ring2 _ringPrimary' : ''}`) },
                div({ class: css('_cursor[grab] _fgmuted') }, icon('grip-vertical')),
                div({ class: css('_w3 _h3 _r1'), style: `background:${tier.color}` }),
                div({ class: css('_flex1') },
                  div({ class: css('_flex _aic _gap2') },
                    span({ class: css('_fontmedium') }, tier.name),
                    tier.published ? Badge({ variant: 'default', size: 'xs' }, 'Live') : Badge({ variant: 'secondary', size: 'xs' }, 'Draft')
                  ),
                  span({ class: css('_textsm _fgmuted') }, '$', tier.monthlyPrice, '/mo')
                ),
                Button({ variant: 'ghost', size: 'sm', onclick: () => editTier(tier) }, icon('edit-2', { size: '16' })),
                Button({ variant: 'ghost', size: 'sm', onclick: () => deleteTier(tier.id) }, icon('trash-2', { size: '16' }))
              )
            )
          ),
      Button({ variant: 'outline', onclick: () => { setEditing(null); setForm({ ...defaultTier }); } },
        icon('plus', { size: '16', class: css('_mr2') }), 'Add Tier'
      )
    ),
    Card({ class: css('studio-card _p6 _flex _col _gap4') },
      h3({ class: css('_heading5 _mb2') }, editing() ? 'Edit Tier' : 'New Tier'),
      div({ class: css('_flex _col _gap4') },
        div({ class: css('_flex _col _gap2') },
          label({ class: css('_textsm _fontmedium') }, 'Tier Name'),
          Input({ value: form_().name, onchange: (e) => setForm({ ...form_(), name: e.target.value }), placeholder: 'e.g., Supporter, Pro, VIP' })
        ),
        div({ class: css('_flex _col _gap2') },
          label({ class: css('_textsm _fontmedium') }, 'Description'),
          Input({ value: form_().description, onchange: (e) => setForm({ ...form_(), description: e.target.value }), placeholder: 'What subscribers get...' })
        ),
        div({ class: css('_grid _gc2 _gap4') },
          div({ class: css('_flex _col _gap2') },
            label({ class: css('_textsm _fontmedium') }, 'Monthly Price'),
            Input({ type: 'number', value: form_().monthlyPrice, onchange: (e) => setForm({ ...form_(), monthlyPrice: Number(e.target.value) }), placeholder: '5' })
          ),
          div({ class: css('_flex _col _gap2') },
            label({ class: css('_textsm _fontmedium') }, 'Yearly Price'),
            Input({ type: 'number', value: form_().yearlyPrice, onchange: (e) => setForm({ ...form_(), yearlyPrice: Number(e.target.value) }), placeholder: '50' })
          )
        ),
        div({ class: css('_flex _col _gap2') },
          label({ class: css('_textsm _fontmedium') }, 'Benefits'),
          div({ class: css('_flex _gap2') },
            Input({ value: newBenefit(), onchange: (e) => setNewBenefit(e.target.value), placeholder: 'Add a benefit...', class: css('_flex1') }),
            Button({ variant: 'outline', onclick: addBenefit }, icon('plus'))
          ),
          form_().benefits.length > 0 ? div({ class: css('_flex _col _gap2 _mt2') },
            ...form_().benefits.map((b, i) =>
              div({ class: css('_flex _aic _gap2 _p2 _bgmuted/5 _r2') },
                icon('check', { size: '16', class: css('_fgSuccess') }),
                span({ class: css('_flex1 _textsm') }, b),
                Button({ variant: 'ghost', size: 'sm', onclick: () => removeBenefit(i) }, icon('x', { size: '14' }))
              )
            )
          ) : null
        ),
        div({ class: css('_flex _aic _jcsb') },
          div({ class: css('_flex _aic _gap2') },
            Switch({ checked: form_().published, onchange: (e) => setForm({ ...form_(), published: e.target.checked }) }),
            span({ class: css('_textsm') }, 'Publish immediately')
          ),
          div({ class: css('_flex _gap2') },
            editing() ? Button({ variant: 'ghost', onclick: () => { setEditing(null); setForm({ ...defaultTier }); } }, 'Cancel') : null,
            Button({ variant: 'primary', onclick: saveTier, disabled: !form_().name }, editing() ? 'Save Changes' : 'Create Tier')
          )
        )
      )
    )
  );
}

