function CompactTierBuilder({ tiers, onEdit, onAdd }) {
  const { div, span } = tags;

  return div({ class: css('_flex _col _gap3') },
    ...tiers.map(tier =>
      Card({ class: css('studio-card _p4 _flex _aic _jcsb'), onclick: () => onEdit(tier) },
        div({ class: css('_flex _aic _gap3') },
          div({ class: css('_w2 _h8 _r1'), style: `background:${tier.color}` }),
          div({},
            span({ class: css('_fontmedium') }, tier.name),
            div({ class: css('_textsm _fgmuted') }, '$', tier.monthlyPrice, '/mo')
          )
        ),
        icon('chevron-right', { class: css('_fgmuted') })
      )
    ),
    Button({ variant: 'outline', onclick: onAdd }, icon('plus', { class: css('_mr2') }), 'Add Tier')
  );
}

